import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toppingsList from '../toppings';
import he from '../i18n/he.json';

const BASE_PRICE = 30;
const TOPPING_PRICE = 8;

export default function PizzaMenu() {
  const [selectedToppings, setSelectedToppings] = useState([]);
  const navigate = useNavigate();

  const handleToppingChange = (topping) => {
    setSelectedToppings((prev) =>
      prev.includes(topping)
        ? prev.filter((t) => t !== topping)
        : [...prev, topping]
    );
  };

  const handleAddToCart = () => {
    const cart = {
      toppings: selectedToppings,
      total: BASE_PRICE + selectedToppings.length * TOPPING_PRICE,
    };
    localStorage.setItem('cart', JSON.stringify(cart));
    navigate('/cart');
  };

  return (
    <div className="max-w-md mx-auto mt-10 p-6 bg-white rounded-lg shadow-lg">
      <h1 className="text-3xl font-bold text-tomato mb-4 text-center">{he.app_title}</h1>
      <img src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=400&q=80" alt="pizza" className="w-full rounded-lg mb-4 shadow" />
      <h2 className="text-xl font-semibold mb-2">{he.menu_title}</h2>
      <div className="mb-4">
        <div className="flex justify-between mb-2">
          <span>{he.base_pizza}</span>
          <span>{BASE_PRICE} ₪</span>
        </div>
        <div className="mb-2 font-semibold">{he.toppings} ({TOPPING_PRICE} ₪)</div>
        <div className="flex flex-wrap gap-2">
          {toppingsList.map((topping) => (
            <label key={topping} className="flex items-center gap-1 bg-crust px-2 py-1 rounded-lg cursor-pointer">
              <input
                type="checkbox"
                checked={selectedToppings.includes(topping)}
                onChange={() => handleToppingChange(topping)}
                className="accent-tomato"
              />
              {topping}
            </label>
          ))}
        </div>
      </div>
      <button
        className="w-full bg-tomato text-white py-2 rounded-lg font-bold text-lg hover:bg-red-700 transition"
        onClick={handleAddToCart}
      >
        {he.cart} ({BASE_PRICE + selectedToppings.length * TOPPING_PRICE} ₪)
      </button>
    </div>
  );
}
